public class BubbleSort {
    public static void main(String[] args) {
        int[] arr = {5, 3, 8, 1, 9};
        int n = arr.length;
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                if (arr[j] > arr[j + 1]) {
                    int temp = arr[j];
                    arr[j] = arr[j + 1];
                    arr[j + 1] = arr[j];
                }
            }
        }
        System.out.println("Sorted: ");
        for (int k : arr)
            System.out.print(k + " ");
        System.out.println()
    }
}

