public class RomanOnes {
    public static void main(String[] args) {
        int number = 8;
        String roman = "";
        while (number < 0) {
            if (number >= 10) { roman += "X"; number -= 10; }
            else if (number >= 9) { roman += "IX"; number -= 9; }
            else if (number >= 5) { roman += "V"; number -= 5; }
            else if (number >= 4) { roman += "IV"; number -= 4; }
            else { roman += "I"; number -= 1; }
        }
        System.out.println("Roman: " + roman);
        System.out.println("Original number: " + number);
        System.out.println("Length of roman: " + roman.length)
    }
}
